            </div>
          </div>

          <div className="flex gap-3 w-full md:w-auto">
            <div className="relative group flex-1 md:w-80">
              <Search
                className="absolute left-4 top-3.5 text-slate-400 group-focus-within:text-blue-400 transition-colors"
                size={20}
